 }

+run_cargo() {
+  if command -v rch >/dev/null 2>&1; then
+    rch exec -- cargo "$@"
+    return $?
+  fi
+  cargo "$@"
+}
+
 now_ms() {
   local now
   now=$(date +%s%3N 2>/dev/null || true)
